package com.hospital.management.validation;import com.hospital.management.model.PaymentForm;import java.math.*;import java.util.*;/** Validates offline payment metadata and balance limits. */public class PaymentValidator{private static final Set<String>METHODS=Set.of("CASH","CARD","UPI","BANK_TRANSFER","INSURANCE");public ValidationResult validate(PaymentForm f,BigDecimal balance){ValidationResult v=new ValidationResult();if(f==null){v.addError("form","Payment is required");return v;}if(f.getBillId()==null||f.getBillId()<=0)v.addError("billId","Invalid bill");BigDecimal a=null;try{a=new BigDecimal(f.getAmount()==null?"":f.getAmount().trim());if(a.signum()<=0||a.scale()>2)v.addError("amount","Enter a positive amount with at most two decimals");else if(balance!=null&&a.compareTo(balance)>0)v.addError("amount","Amount cannot exceed the current balance");}catch(Exception e){v.addError("amount","Enter a valid amount");}String m=f.getPaymentMethod()==null?"":f.getPaymentMethod().toUpperCase();if(!METHODS.contains(m))v.addError("paymentMethod","Select a valid payment method");String r=f.getTransactionReference()==null?"":f.getTransactionReference().trim();if(!"CASH".equals(m)&&r.isBlank())v.addError("transactionReference","Transaction reference is required");if(r.length()>150)v.addError("transactionReference","Reference cannot exceed 150 characters");return v;}}
